def normalize_preference(value: Optional[str]) -> str:
    if not value:
        return "normal"
    v = value.strip().lower().replace("_", " ").replace("-", " ")
    mapping = {
        "none": "normal", "all": "normal", "balanced": "normal", "normal": "normal",
        "vegetarian": "vegetarian", "vegan": "vegan", "pescatarian": "pescatarian",
        "keto": "low_carb", "low carb": "low_carb", "high protein": "high_protein",
        "dairy free": "dairy_free", "gluten free": "gluten_free",
    }
    return mapping.get(v, v.replace(" ", "_"))


def food_allowed(food: FoodRecord, dietary_preference: Optional[str]) -> bool:
    pref = normalize_preference(dietary_preference)
    if pref == "normal":
        return True
    tags = set(food.get("dietary_tags", []))
    category = food.get("category")
    if pref == "vegan":
        return "vegan" in tags and category not in {"red_meat", "white_meat", "fish_seafood", "dairy", "eggs"}
    if pref == "vegetarian":
        return category not in {"red_meat", "white_meat", "fish_seafood"}
    if pref == "pescatarian":
        return category not in {"red_meat", "white_meat"}
    return pref in tags


def get_food_by_id(food_id: str) -> FoodRecord | None:
    return next((food for food in FOOD_CATALOG if food["id"] == food_id), None)


def filter_foods(category: str | None = None, search: str | None = None, dietary_preference: str | None = None, limit: int = 50, offset: int = 0) -> dict:
    q = (search or "").strip().lower()
    rows = []
    for food in FOOD_CATALOG:
        if category and food["category"] != category:
            continue
        if q and q not in food["id"].lower() and q not in food["name_en"].lower() and q not in food["name_ar"].lower():
            continue
        if not food_allowed(food, dietary_preference):
            continue
        rows.append(food)
    return {"total": len(rows), "limit": limit, "offset": offset, "items": rows[offset: offset + limit]}


def get_categories_summary() -> list[dict]:
    counts: dict[str, int] = {}
    for food in FOOD_CATALOG:
        counts[food["category"]] = counts.get(food["category"], 0) + 1
    return [{"key": key, "name": key.replace("_", " ").title(), "count": count} for key, count in sorted(counts.items())]
